import java.util.*;

public class GreedyPrim {

    public int buildMST(int V, int[][] edges) {
        // Build adjacency list: {neighbor, weight}
        List<int[]>[] adj = new ArrayList[V];
        for (int i = 0; i < V; i++) adj[i] = new ArrayList<>();
        for (int[] e : edges) {
            adj[e[0]].add(new int[]{e[1], e[2]});
            adj[e[1]].add(new int[]{e[0], e[2]});
        }

        boolean[] visited = new boolean[V];
        // PriorityQueue of {weight, from, to}
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));
        visited[0] = true;
        for (int[] nb : adj[0]) pq.offer(new int[]{nb[1], 0, nb[0]});

        int totalWeight = 0, edgeCount = 0;
        System.out.println("MST edges:");
        while (!pq.isEmpty() && edgeCount < V - 1) {
            int[] entry = pq.poll();
            int w = entry[0], from = entry[1], to = entry[2];
            if (visited[to]) continue;
            // TODO: mark to as visited, add w to totalWeight, increment edgeCount
            //       print edge, then enqueue all unvisited neighbors of 'to'
        }
        return totalWeight;
    }

    public static void main(String[] args) {
        GreedyPrim gp = new GreedyPrim();
        int[][] edges = {{0,1,2},{0,3,6},{1,2,3},{1,3,8},{1,4,5},{2,4,7},{3,4,9}};
        int total = gp.buildMST(5, edges);
        System.out.println("Total MST weight: " + total);
    }
}

import java.util.*;

public class GreedyKruskal {
    int[] parent, rank;

    void init(int n){parent=new int[n];rank=new int[n];for(int i=0;i<n;i++)parent[i]=i;}
    int find(int x){return parent[x]==x?x:(parent[x]=find(parent[x]));}
    boolean union(int a,int b){int ra=find(a),rb=find(b);if(ra==rb)return false;
        if(rank[ra]<rank[rb])parent[ra]=rb;else if(rank[ra]>rank[rb])parent[rb]=ra;
        else{parent[rb]=ra;rank[ra]++;} return true;}

    public int buildMST(int V, int[][] edges) {
        init(V);
        // TODO: sort edges by weight
        int totalWeight = 0, edgeCount = 0;
        System.out.println("Kruskal process:");
        for (int[] e : edges) {
            if (edgeCount == V - 1) break;
            // TODO: if union(e[0],e[1]) succeeds: print "ADD", accumulate weight, increment count
            //       else: print "SKIP (cycle)"
        }
        return totalWeight;
    }

    public static void main(String[] args) {
        GreedyKruskal gk = new GreedyKruskal();
        int[][] edges = {{0,1,2},{0,3,6},{1,2,3},{1,3,8},{1,4,5},{2,4,7},{3,4,9}};
        int total = gk.buildMST(5, edges);
        System.out.println("Total MST weight: " + total);
    }
}

import java.util.*;

public class DijkstraGreedy {

    public int[] dijkstra(int V, List<int[]>[] adj, int src) {
        int[] dist = new int[V];
        Arrays.fill(dist, Integer.MAX_VALUE);
        dist[src] = 0;
        // PriorityQueue of {dist, vertex}
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a->a[0]));
        pq.offer(new int[]{0, src});
        boolean[] finalized = new boolean[V];

        System.out.println("Greedy selections:");
        while (!pq.isEmpty()) {
            int[] cur = pq.poll();
            int d = cur[0], u = cur[1];
            if (finalized[u]) continue;
            finalized[u] = true;
            System.out.println("  Finalize vertex " + u + " with dist=" + d);
            // TODO: for each edge (u->v, w): if dist[u]+w < dist[v], update and enqueue
        }
        return dist;
    }

    @SuppressWarnings("unchecked")
    public static void main(String[] args) {
        int V = 5;
        List<int[]>[] adj = new ArrayList[V];
        for (int i=0;i<V;i++) adj[i]=new ArrayList<>();
        int[][] edges={{0,1,4},{0,2,8},{1,2,11},{1,3,8},{2,4,7},{3,4,9},{3,2,2},{4,3,1}};
        for (int[] e:edges) adj[e[0]].add(new int[]{e[1],e[2]});
        DijkstraGreedy dg = new DijkstraGreedy();
        int[] d = dg.dijkstra(V, adj, 0);
        System.out.println("Distances from 0: " + Arrays.toString(d));
    }
}
